<template>
  <div ref="containerRef" class="container-width">
    <v-container fluid>
      <v-row class="text-center">
        <v-col cols="12" class="overflow-c">
          <div ref="tableRef">
            <v-data-table
              :headers="filteredHeaders"
              :items="deliverables"
              hide-default-header
              hide-default-footer
              :sort-by.sync="sortBy"
              disable-pagination
              :sort-desc.sync="sortDesc"
              class="elevation-1 zoom custom-data-table "
            >
              <template v-slot:header="{ props: { headers } }">
                <thead class="v-data-table-header">
                  <!-- Toppest Row -->
                  <tr ref="headerRef">
                    <th
                      style="border: solid 0.5px; padding: 0px 0px;"
                      v-for="header in headers"
                      v-bind:key="header.value"
                    >
                      <span></span>
                      <span style="height: 100%" v-if="header.value.includes('step')">
                        <v-progress-linear
                          :value="stepsFulfillment[header.value]"
                          color="green"
                          :height="thHeight"
                          reactive
                          striped
                        >
                          {{ stepsFulfillment[header.value] ? Math.round(stepsFulfillment[header.value]) : 0 }}%
                        </v-progress-linear>
                        <!-- 
                        <div class="v-progress-linear v-progress-linear--striped v-progress-linear--visible theme--light">
                          <div class="v-progress-linear__background green" :style="{
                            opacity: 0.3,
                            left: getProgressBarStyles(header, stepsFulfillment),
                            width: (stepsFulfillment[header.value] ? 100 - Math.round(stepsFulfillment[header.value]) : 100) + '%'
                          }">
                          </div>

                          <div class="v-progress-linear__buffer"></div>

                          <div class="v-progress-linear__determinate green"
                            :style="{ width: getProgressBarStyles(header, stepsFulfillment) }"></div>
                          <div class="v-progress-linear__content">
                            {{
                              stepsFulfillment[header.value]
                              ? Math.round(stepsFulfillment[header.value])
                              : 0
                            }}%
                          </div>
                        </div> -->
                      </span>
                      <span v-else-if="header.value === 'fulfillment'">
                        <!-- <v-progress-linear
                          :value="totalFulfillment !== null && !isNaN(totalFulfillment) ? totalFulfillment : 0"
                          color="green" :height="thHeight" reactive striped>
                          {{ totalFulfillment !== null && !isNaN(totalFulfillment) ? totalFulfillment + '%' : 'n.rel.' }}
                        </v-progress-linear> -->

                        <div
                          class="v-progress-linear v-progress-linear--striped v-progress-linear--visible theme--light"
                        >
                          <div
                            class="v-progress-linear__background green"
                            :style="{
                              opacity: 0.3,
                              left: totalFulfillment + '%',
                              width: totalFulfillment ? 100 - totalFulfillment + '%' : 100 + '%',
                            }"
                          ></div>

                          <div class="v-progress-linear__buffer"></div>

                          <div
                            class="v-progress-linear__determinate green"
                            :style="{ width: totalFulfillment + '%' }"
                          ></div>
                          <div class="v-progress-linear__content">
                            {{
                              totalFulfillment !== null && !isNaN(totalFulfillment) ? totalFulfillment + "%" : "n.rel."
                            }}
                          </div>
                        </div>
                      </span>

                      <div v-else style="color: white;" @click="toggleWidth()">
                        '
                      </div>
                    </th>
                  </tr>

                  <!-- Second toppest Row -->
                  <tr class="secondTopRow">
                    <!-- & -->
                    <th
                      id="tableHeader"
                      v-for="(header, idx) in headers"
                      :key="idx"
                      role="columnheader"
                      scope="col"
                      :aria-label="`${header.text}: Sorted ascending. Activate to sort descending.`"
                      aria-sort="ascending"
                      class="sortable"
                      :class="{
                        active: sortBy === header.value,
                        asc: sortDesc === false,
                      }"
                    >
                      <!-- Step's header edit dialog -->
                      <v-edit-dialog
                        class=""
                        v-if="header.headerEditable"
                        @open="headerTextFieldOpen(header.text)"
                        @save="changeHeader(header)"
                      >
                        <!-- step title -->
                        <span>
                          <span>
                            {{ header.text }}
                          </span>
                          <!-- edit text field -->
                        </span>
                        <template v-slot:input>
                          <v-text-field
                            @focus="$event.target.select()"
                            :value="header.text"
                            @change="inputChanged($event)"
                            :rules="[rules.required, rules.alreadyExist]"
                            counter
                            maxlength="20"
                            label="Edit"
                            single-line
                          ></v-text-field>
                        </template>
                      </v-edit-dialog>

                      <!-- <span> -->
                      <span id="deleteIcon" v-if="header.headerEditable" @click="conformMessage('', idx, 'column')">
                        <v-icon small>mdi-delete</v-icon>
                      </span>

                      <!-- non step columns -->
                      <span v-else>
                        <span @click="sortColumn(header.value)">
                          <!-- non step columns title -->
                          <span>{{ header.text }} </span>
                          <span>
                            <!-- The arrow -->
                            <i
                              :style="{
                                transform: `rotate(${rotateValues[header.value]}deg)`,
                              }"
                              @click="rotateValues[header.value] += rotateValues[header.value] === 0 ? -180 : 180"
                              aria-hidden="true"
                              class="v-icon notranslate v-data-table-header__icon mdi mdi-arrow-up theme--light"
                              style="font-size: 18px; transition: transform 0.25s linear;"
                            ></i>
                          </span>
                        </span>
                      </span>
                      <!-- </span> -->
                    </th>
                  </tr>
                </thead>
              </template>
              <template v-slot:body="{ items, headers }">
                <tbody>
                  <template v-for="(item, idx) in items">
                    <tr ref="rowRef">
                      <td
                        @mouseover="item.showEditDialog = true"
                        @mouseleave="mouseLeave(item)"
                        :title="expandedWidth ? getTitle(item, header) : ''"
                        v-for="(header, key) in headers"
                        :key="`inner_${key}`"
                        :style="cellBackgroundStyle(item[header.value])"
                        :class="{ 'expanded-td': expandedWidth }"
                      >
                        <!-- <span v-else> -->
                        <!-- header editable -->
                        <span v-if="header.editable">
                          <span v-if="!item.showEditDialog && !item.isChild">{{ item[header.value] }}</span>

                          <span v-else>
                            <!-- isChild -->
                            <template v-if="header.value.includes('step')">
                              <!-- Render the value without v-edit-dialog for steps cell -->
                              <!-- Render the value without for child project stepsfulfillment value -->
                              <span v-if="item.isChild">
                                {{ item[header.value] ? Math.round(item[header.value]) : 0 }}%
                              </span>

                              <span v-else @click="handleSelectChange(item, header.value)" style="cursor: pointer;">
                                {{ item[header.value] }}
                              </span>
                            </template>
                            <template v-else>
                              <v-edit-dialog
                                @close="close1(item)"
                                @cancel="cancel"
                                @open="open(item[header.value])"
                                @save="changeCell(item, header.value)"
                              >
                                {{ item[header.value] }}
                                <template v-slot:input>
                                  <span>
                                    <v-text-field
                                      type="number"
                                      :rules="[rules.required, rules.positiveNumbers]"
                                      v-if="header.text === 'Weight'"
                                      @focus="$event.target.select()"
                                      :value="item[header.value]"
                                      @change="inputChanged($event, 'weight')"
                                      label="Edit"
                                      single-line
                                    ></v-text-field>
                                    <v-text-field
                                      v-else
                                      @focus="$event.target.select()"
                                      :value="item[header.value]"
                                      @change="inputChanged($event)"
                                      label="Edit"
                                      single-line
                                    ></v-text-field>
                                  </span>
                                </template>
                              </v-edit-dialog>
                            </template>

                            <!-- <v-edit-dialog @close="close1(item)" @cancel="cancel" @open="open(item[header.value])"
                            @save="changeCell(item, header.value)">
                            This value is showing at every editable cell whenever mouse hover on it.
                            {{ item[header.value] }}
                            <template v-slot:input>
                              <v-select v-if="header.value.includes('step')" :items="selectItems"
                                :value="item[header.value]" @change="
                                  inputChanged($event),
                                  changeCell(item, header.value)
                                  "></v-select>
                              <span v-else>
                                text field for weight  
                                <v-text-field type="number" :rules="[
                                  rules.required,
                                  rules.positiveNumbers
                                ]" v-if="header.text === 'Weight'" @focus="$event.target.select()"
                                  :value="item[header.value]" @change="inputChanged($event, 'weight')" label="Edit"
                                  single-line></v-text-field>
                                text field for description editing
                                <v-text-field v-else @focus="$event.target.select()" :value="item[header.value]"
                                  @change="inputChanged($event)" label="Edit" single-line></v-text-field>
                              </span>
                            </template>
                          </v-edit-dialog> -->
                          </span>
                        </span>

                        <!-- header not editable -->
                        <span v-else>
                          <span v-if="header.value === 'fulfillment'">
                            <v-progress-linear
                              :value="typeof item[header.value] === 'number' ? item[header.value] : 0"
                              color="green"
                              :height="tdHeight"
                              reactive
                              striped
                            >
                              {{
                                typeof item[header.value] === "number" ? Math.round(item[header.value]) + "%" : "n.rel."
                              }}
                            </v-progress-linear>
                          </span>

                          <!-- The ID  -->
                          <div
                            v-else
                            @click="handleClick(idx, item[header.value], $event)"
                            :class="{ 'selected-row': isSelected(idx) }"
                            style="cursor: pointer;"
                          >
                            <!-- <div class="d-inline"> -->
                            {{ item[header.value] }}
                            <!-- </div> -->
                            <!-- <div @click="
                            conformMessage(
                              `Do you want to delete row ${idx + 1} ?`,
                              idx,
                              'Row'
                            )
                            " id="rowDeleteIcon" style="border: 1px solid rgba(255, 0, 0, 0); min-width: 20px; ">
                            <v-icon small>mdi-delete</v-icon>
                          </div> -->
                          </div>
                        </span>
                        <!-- </span> -->
                      </td>
                    </tr>

                    <!-- Check if the current row has children -->
                    <template ref="rowRef" v-if="item.children && item.children.length > 0">
                      <!-- Nested loop to render children rows -->
                      <tr v-for="(child, childIdx) in item.children" :key="`child_${idx}_${childIdx}`">
                        <td
                          @mouseover="child.showEditDialog = true"
                          @mouseleave="mouseLeave(child)"
                          :title="expandedWidth ? getTitle(child, header) : ''"
                          v-for="(header, index) in headers"
                          :key="`inner_child_${index}`"
                          :style="cellBackgroundStyle(child[header.value])"
                          :class="{ 'expanded-td': expandedWidth }"
                        >
                          <!-- <span v-else> -->
                          <!-- header editable -->
                          <span v-if="header.editable">
                            <span v-if="!child.showEditDialog">{{ child[header.value] }}</span>
                            <span v-else>
                              <!-- isChild -->
                              <template v-if="header.value.includes('step')">
                                <!-- Render the value without v-edit-dialog for steps cell -->
                                <!-- Render the value without for child project stepsfulfillment value -->
                                <!-- <span v-if="child.isChild">
                                  {{ child[header.value] ? Math.round(child[header.value]) + "%" : 0 }}
                                </span> -->

                                <span @click="handleSelectChange(child, header.value)" style="cursor: pointer;">
                                  {{ child[header.value] }}
                                </span>
                              </template>
                              <template v-else>
                                <v-edit-dialog
                                  @close="close1(child)"
                                  @cancel="cancel"
                                  @open="open(child[header.value])"
                                  @save="changeCell(child, header.value)"
                                >
                                  {{ child[header.value] }}
                                  <template v-slot:input>
                                    <span>
                                      <v-text-field
                                        type="number"
                                        :rules="[rules.required, rules.positiveNumbers]"
                                        v-if="header.text === 'Weight'"
                                        @focus="$event.target.select()"
                                        :value="child[header.value]"
                                        @change="inputChanged($event, 'weight')"
                                        label="Edit"
                                        single-line
                                      ></v-text-field>
                                      <v-text-field
                                        v-else
                                        @focus="$event.target.select()"
                                        :value="item[header.value]"
                                        @change="inputChanged($event)"
                                        label="Edit"
                                        single-line
                                      ></v-text-field>
                                    </span>
                                  </template>
                                </v-edit-dialog>
                              </template>

                              <!-- <v-edit-dialog @close="close1(item)" @cancel="cancel" @open="open(item[header.value])"
                            @save="changeCell(item, header.value)">
                            This value is showing at every editable cell whenever mouse hover on it.
                            {{ item[header.value] }}
                            <template v-slot:input>
                              <v-select v-if="header.value.includes('step')" :items="selectItems"
                                :value="item[header.value]" @change="
                                  inputChanged($event),
                                  changeCell(item, header.value)
                                  "></v-select>
                              <span v-else>
                                text field for weight  
                                <v-text-field type="number" :rules="[
                                  rules.required,
                                  rules.positiveNumbers
                                ]" v-if="header.text === 'Weight'" @focus="$event.target.select()"
                                  :value="item[header.value]" @change="inputChanged($event, 'weight')" label="Edit"
                                  single-line></v-text-field>
                                text field for description editing
                                <v-text-field v-else @focus="$event.target.select()" :value="item[header.value]"
                                  @change="inputChanged($event)" label="Edit" single-line></v-text-field>
                              </span>
                            </template>
                          </v-edit-dialog> -->
                            </span>
                          </span>

                          <!-- header not editable -->
                          <span v-else>
                            <span v-if="header.value === 'fulfillment'">
                              <v-progress-linear
                                :value="typeof child[header.value] === 'number' ? child[header.value] : 0"
                                color="green"
                                :height="tdHeight"
                                reactive
                                striped
                              >
                                {{
                                  typeof child[header.value] === "number"
                                    ? Math.round(child[header.value]) + "%"
                                    : "n.rel."
                                }}
                              </v-progress-linear>
                            </span>

                            <!-- The ID  -->
                            <div
                              v-else
                              @click="handleClick(idx, item[header.value], $event)"
                              :class="{ 'selected-row': isSelected(idx) }"
                              style="cursor: pointer;"
                            >
                              <!-- <div class="d-inline"> -->
                              {{ child[header.value] }}
                              <!-- </div> -->
                              <!-- <div @click="
                            conformMessage(
                              `Do you want to delete row ${idx + 1} ?`,
                              idx,
                              'Row'
                            )
                            " id="rowDeleteIcon" style="border: 1px solid rgba(255, 0, 0, 0); min-width: 20px; ">
                            <v-icon small>mdi-delete</v-icon>
                          </div> -->
                            </div>
                          </span>
                          <!-- </span> -->
                        </td>
                        <!-- <td v-for="(header, key) in headers" :key="key">
                          Render child data here
                          You can use the same logic as in the main row to render cells based on headers
                          {{ child[header.value] }}
                        </td> -->
                      </tr>
                    </template>
                  </template>

                  <div class="toolbox" v-if="toolboxVisible" :style="{ top: selectedRowTop + 'px' }">
                    <v-icon small @click="deleteRows">mdi-delete</v-icon>
                    <v-icon small @click="createNewRowFromSelected">mdi-arrow-right</v-icon>
                  </div>
                </tbody>
              </template>
              <template v-slot:top>
                <v-toolbar height="32" class="mb-0 mt-0" flat color="white">
                  <v-toolbar-title>Tasks</v-toolbar-title>
                  <v-divider class="mx-4" inset vertical></v-divider>
                  <v-btn x-small color="primary" dark class="mb-2" @click="generateExcel">Generate Excel</v-btn>

                  <v-btn x-small color="primary" dark class="mb-2 ml-2" @click="adjustSize">{{ adjustText }}</v-btn>

                  <v-btn x-small color="primary" dark class="mb-2 ml-2" @click="addRow">Add Row</v-btn>
                  <v-divider class="mx-4" inset vertical></v-divider>

                  <v-file-input
                    dense
                    v-model="file"
                    placeholder="Load excel file"
                    label="File input"
                    prepend-icon="mdi-paperclip"
                    show-size
                    @change="loadExcel"
                  >
                    <template v-slot:selection="{ text }">
                      <v-chip small label color="primary">{{ text }}</v-chip>
                    </template>
                  </v-file-input>
                  <v-divider class="mx-4" inset vertical></v-divider>

                  <v-spacer></v-spacer>
                  <v-btn x-small color="primary" dark class="mr-2 mb-2" @click="undoDelete"> UNDELET </v-btn>
                  <v-btn x-small color="primary" dark class="mb-2" @click="toggleWeight">{{ showWeight }}</v-btn>
                  <AddColumn />
                </v-toolbar>
              </template>
            </v-data-table>
          </div>
        </v-col>
      </v-row>
    </v-container>
    <div v-if="showConformMessage">
      <ConfirmMessage
        :message="message"
        :pressedType="pressedType"
        @deleteRow="deleteRow"
        @deleteStep="deleteColumn('step')"
        @deleteResponsible="deleteColumn('responsible')"
        @dontDelete="toggleShowConformMessage"
      />
    </div>
  </div>
</template>

<script>
import ExcelOperator from "../utils/excel-operator";
import FulfilmentsUtil from "../utils/fulfilments-util";
import AddColumn from "@/components/AddColumn";
import ConfirmMessage from "@/components/ConfirmMessage";
import { mapState } from "vuex";
const util = new FulfilmentsUtil();

export default {
  name: "HelloWorld",
  components: {
    AddColumn,
    ConfirmMessage,
  },
  data: () => ({
    selectedRowTop: 0,
    selectedRows: [], // Track selected rows by index
    deletedRows: [],
    deletedRowsStack: [],
    isShiftPressed: false,
    toolboxVisible: false,
    newRowCounter: 0,
    expandedWidth: true,
    isDialogOpen: false,
    showEditDialog: true,
    selectItems: ["open", "wip", "closed", "n.rel."],
    rotateValues: { id: 0, description: 0, weight: 0, fulfillment: 0 },
    sortBy: "id",
    sortDesc: false,
    file: null,
    inputValue: "",
    showWeight: "Show Weight",
    max20chars: (v) => v.length <= 20 || "Maximum 20 character allowed",
    rules: {
      counter: (value) => value.length <= 20 || "Max 20 characters",
      required: (value) => !!value || "Required.",
      positiveNumbers: (value) => value > 0 || "Should be greater than 0",
      alreadyExist: true,
    },

    adjustText: "Fit On Page",
    heightScale: 0,
    widthScale: 0,
    horizontalAdjusted: false,

    thHeight: 16,
    thWidth: 0,
    tdHeight: 16,
    headerEditValue: "",

    defaultItem: {
      id: "",
      description: "",
      oneWeekBefore: "",
      untilDayBefore: "",
      fulfillment: 0,
    },
    stepOffset: 3,
    // Added by MMG
    showDeleteIcon: false,
    columnDeleteIcon: false,
    message: "The Message",
    pressedId: "",
    pressedType: "",
    showConformMessage: false,
  }),
  computed: {
    stepsFulfillment() {
      return this.$store.getters.stepsFulfillment;
    },
    ...mapState(["statusTable"]),
    headers() {
      return this.statusTable.headers;
    },
    filteredHeaders() {
      // console.log('headers arr', this.statusTable.headers)
      // Add a checkbox header
      return this.statusTable.headers.filter((item) => {
        if (this.showWeight === "Show Weight") {
          return item.value !== "weight";
        } else {
          return true;
        }
      });
    },
    deliverables() {
      return this.statusTable.deliverables;
    },
    responsibles() {
      return this.statusTable.responsibles;
    },
    steps() {
      return this.statusTable.steps;
    },
    totalFulfillment() {
      return Math.round(this.$store.getters.totalFulfillment);
    },
  },
  mounted: function() {
    this.$nextTick(function() {
      // Code that will run only after the
      // entire view has been rendered
      if (this.$refs.headerRef) this.thHeight = this.$refs.headerRef.clientHeight;
      this.thWidth = this.$refs.headerRef.clientWidth;
      if (this.$refs.rowRef) this.tdHeight = this.$refs.rowRef[0].clientHeight;

      const tableToolbarHeight = document.getElementsByClassName("v-toolbar__content")[0].clientHeight;
      const containerHeight = document.getElementsByClassName("overflow-c")[0].clientHeight;
      const tableWrapper = document.getElementsByClassName("v-data-table__wrapper")[0];
      tableWrapper.style.maxHeight = containerHeight - tableToolbarHeight + "px";
      const savedCounter = localStorage.getItem("newRowCounter");
      if (savedCounter) {
        this.newRowCounter = parseInt(savedCounter, 10);
      }
    });
  },
  watch: {
    dialog(val) {
      val || this.close();
    },
  },

  methods: {
    renumberDeliverables(deliverables) {
      return deliverables.map((row, index) => {
        return { ...row, id: index + 1 };
      });
    },

    getChildRowCounter() {
      this.newRowCounter++;
      // Save the counter to localStorage
      localStorage.setItem("newRowCounter", this.newRowCounter.toString());
    },

    createNewRowFromSelected() {

      if (this.selectedRows.some((idx) => this.deliverables[idx].isGrouped)) {
        alert("Cannot regroup already grouped rows");
        return;
      }

      this.getChildRowCounter();

      if (this.selectedRows.length > 0) {
        // Create a new row object with default values
        const newRow = {
          description: "child project",
          fulfillment: 0,
          id: this.newRowCounter,
          responsible: "",
          showEditDialog: false,
          weight: 0,
          isChild: true,
          children: [],
          isGrouped: true,
        };

        // Calculate the total weight and fulfillment for the selected rows
        let totalWeight = 0;
        let newRowId = newRow.id;

        console.log("new row id ", newRowId);

        // Update the selected rows and move them to the children property of the new row
        newRow.children = this.selectedRows.map((idx, index) => {
          const selectedRow = { ...this.deliverables[idx] }; // Create a deep copy
          selectedRow.id = `${newRow.id}.${index + 1}`; // Update the ID as 1.1, 1.2, 1.3, etc.
          totalWeight += selectedRow.weight;
          selectedRow.parentNum = newRow.id;
          selectedRow.isGrouped = true;
          return selectedRow;
        });
        // Set the calculated values to the new row
        newRow.weight = totalWeight;

        // Remove the selected rows from the deliverables array
        let updatedDeliverables = this.deliverables.filter((_, idx) => !this.selectedRows.includes(idx));

        // Calculate percentages and values for each step
        this.calculateStepsFulfillmentForNewRow(newRow);

        // Find the index where the new row should be inserted based on the 'id'
        const insertIndex = updatedDeliverables.findIndex((row) => newRow.id < row.id);

        // If insertIndex is -1, it means the new row should be added at the end
        const finalIndex = insertIndex !== -1 ? insertIndex : updatedDeliverables.length;

        // Insert the new row at the calculated position
        updatedDeliverables.splice(finalIndex, 0, newRow);
        // updatedDeliverables.unshift(newRow)

        console.log("updated deliverables ", updatedDeliverables);

        updatedDeliverables = this.renumberDeliverables(updatedDeliverables);


        // Clear selection after creating the new row
        this.selectedRows = [];

        //Hide the toolbox
        this.toolboxVisible = false;

        // Update the store
        this.$store.dispatch("setDeliverables", updatedDeliverables);
        // console.log("new deliverables", this.deliverables);
      }
    },

    calculateStepsFulfillmentForNewRow(row) {
      // Calculate percentages based on total weight and fulfillment
      if (row.weight > 0) {
        let sumAll = 0;
        // let totalWeights = 0;

        this.steps.forEach((step) => {
          let totalWeights = 0;
          let wipCount = 0;
          let closedCount = 0;

          row.children.forEach((item, idx) => {
            // const selectedRow = this.deliverables[idx];
            if (item[step.identity] !== "n.rel.") {
              totalWeights += item.weight;
            }
            closedCount += item[step.identity] === "closed" ? 1 * item.weight : 0;
            wipCount += item[step.identity] === "wip" ? 0.5 * item.weight : 0;
          });
          // const stepValue = row[step.identity];
          row[step.identity] = ((closedCount + wipCount) / totalWeights) * 100;
        });

        // calculate the totalfulfillment for the selected rows.
        if (this.steps.length > 0) {
          let totalWeights = 0;
          row.children.forEach((item, idx) => {
            // const selectedRow = this.deliverables[idx];
            if (typeof item.fulfillment === "number") {
              totalWeights += item.weight;
              sumAll += item.fulfillment * item.weight;
            }
          });
          row.fulfillment = sumAll / totalWeights;
        }
      }
    },

    deleteRows() {
      if (this.selectedRows.length > 0) {
        // Confirm deletion
        // const confirmMessage = `Do you want to delete the selected row(s)?`;
        // if (confirm(confirmMessage)) {
        // Store deleted rows temporarily
        const deletedRows = this.selectedRows.map((idx) => this.deliverables[idx]);
        this.deletedRows.push(...deletedRows);

        // Delete selected rows
        this.selectedRows.sort((a, b) => b - a); // Sort in descending order
        this.selectedRows.forEach((idx) => {
          this.deliverables.splice(idx, 1); // Remove row at index idx
        });

        // Clear selection after deletion
        this.selectedRows = [];

        // Update the stack with the deleted rows
        this.deletedRowsStack.push(deletedRows);

        //Update the toolbox visible
        this.toolboxVisible = false;

        // Recalculate fulfillments
        util.recalculateAllFulfillments(this.deliverables, this.steps);

        // Update the store
        this.$store.dispatch("setDeliverables", this.deliverables);
        // }
      }
    },

    undoDelete() {
      if (this.deletedRowsStack.length > 0) {
        // Pop the last set of deleted rows from the stack
        const lastDeletedRows = this.deletedRowsStack.pop();

        // Restore deleted rows
        this.deliverables.push(...lastDeletedRows);

        // Recalculate fulfillments
        util.recalculateAllFulfillments(this.deliverables, this.steps);

        // Update the store (assuming you're using Vuex)
        this.$store.dispatch("setDeliverables", this.deliverables);
      }
    },

    handleClick(idx, value, event) {
      this.selectLine(idx, value);
      this.handleRowClick(idx, event);
    },

    handleRowClick(idx, event) {
      if (event.shiftKey) {
        // Handle Shift key press
        this.handleShiftClick(idx);
      } else if (event.ctrlKey || event.metaKey) {
        // Handle regular row click with Ctrl or Command key
        this.toggleRowSelection(idx);
      } else {
        // Handle regular row click without Ctrl or Command key
        this.selectedRows = [idx];
        // this.showToolbox = false;
      }
    },

    handleShiftClick(idx) {
      if (this.selectedRows.length === 0) {
        // If no rows are selected, treat it as a regular click
        this.selectedRows = [idx];
      } else {
        // Select the range between the last selected row and the current row
        const start = this.selectedRows[this.selectedRows.length - 1];
        this.selectRange(start, idx);
      }
      // this.showToolbox = false;
    },

    selectRange(start, end) {
      // Clear existing selections and select the range
      this.selectedRows = [];
      const step = start < end ? 1 : -1;
      for (let i = start; i !== end + step; i += step) {
        this.selectedRows.push(i);
      }
    },

    toggleRowSelection(idx) {
      // Check if the row is already selected
      const index = this.selectedRows.indexOf(idx);
      if (index !== -1) {
        // If selected, remove it
        this.selectedRows.splice(index, 1);
      } else {
        // If not selected, add it
        this.selectedRows.push(idx);
      }
    },
    isSelected(idx) {
      // Check if the row is selected
      return this.selectedRows.includes(idx);
    },

    selectLine(index, value) {
      // Set the selectedRowIndex to the current index
      // this.selectedRowIndex = index;
      // console.log('index val', index)
      const rowHeight = 30; // Adjust this based on your table row height
      this.selectedRowTop = index * rowHeight; //
      this.toolboxVisible = true;
    },

    handleSelectChange(item, headerValue) {
      // Assuming steps are defined as an array
      const steps = ["open", "wip", "closed", "n.rel."];

      // Get the current step index
      const currentStepIndex = steps.indexOf(item[headerValue]);

      // Calculate the next step index (cycling back to 0 if at the end)
      const nextStepIndex = (currentStepIndex + 1) % steps.length;

      // Set the new step value
      this.$set(item, headerValue, steps[nextStepIndex]);

      // Recalculate the row
      this.calculateRowFulfillment(item);

      if (item.parentNum !== undefined) {
        console.log("passed item", item);
        // The item is a child, recalculate the parent row
        let parentRow = this.deliverables.find((row) => row.id === item.parentNum);
        this.calculateStepsFulfillmentForNewRow(parentRow);
        console.log("parent row", parentRow);
      }

      // Set the deliverables again.
      this.$store.dispatch("setDeliverables", this.deliverables);
    },

    getProgressBarStyles(header, stepsFulfillment) {
      return (stepsFulfillment[header.value] ? Math.round(stepsFulfillment[header.value]) : 0) + "%";
    },

    toggleWidth() {
      this.expandedWidth = !this.expandedWidth;
    },
    getTitle(item, header) {
      if (header.value.includes("step") || !isNaN(item[header.value])) {
        return "";
      } else {
        return item[header.value];
      }
    },
    toggleWeight() {
      if (this.showWeight === "Show Weight") {
        this.showWeight = "Hide Weight";
      } else {
        this.showWeight = "Show Weight";
      }
    },
    mouseLeave(item) {
      if (!this.isDialogOpen) {
        item.showEditDialog = false;
      }
    },
    headerTextFieldOpen(headerText) {
      this.inputValue = headerText;
      this.rules.alreadyExist = (value) => {
        return (
          !this.headers.find((header) => {
            return (
              value.toLowerCase() === header.text.toLowerCase() && value.toLowerCase() !== headerText.toLowerCase()
            );
          }) || "Column name already exist"
        );
      };
    },
    addRow() {
      let id = 1;
      let tasksLength = this.deliverables.length;
      if (tasksLength !== 0) {
        id = this.deliverables[tasksLength - 1].id + 1;
      }
      const row = {
        id: id,
        description: "",
        responsible: "",
        weight: 1,
        fulfillment: 0,
        showEditDialog: false,
      };

      this.steps.forEach((step) => {
        let identity = step.identity;
        row[identity] = "open";
      });

      this.deliverables.push(row);
      this.$store.dispatch("setDeliverables", this.deliverables);
    },
    //TODO refactor to only have one copy of this method in one place (AddColumn component)
    calculateRowFulfillment(row) {
      console.log("passed row", row);
      let stepsLength = this.steps.length;
      let closedCount = 0;
      let wipCount = 0;

      // if (stepsLength > 0) {
      this.steps.forEach((step) => {
        closedCount += row[step.identity] === "closed" ? 1 : 0;
        wipCount += row[step.identity] === "wip" ? 0.5 : 0;
        stepsLength -= row[step.identity] === "n.rel." ? 1 : 0;
      });
      // }
      if (stepsLength > 0) {
        let fulfillment = ((closedCount + wipCount) / stepsLength) * 100;
        row.fulfillment = fulfillment;
      } else {
        row.fulfillment = "n.rel.";
      }
    },
    // Commected BY MMG
    // deleteItem(item) {
    //   const index = this.deliverables.indexOf(item);
    //   confirm("Are you sure you want to delete this item?") &&
    //     this.deliverables.splice(index, 1);
    //   this.$store.dispatch("setDeliverables", this.deliverables);
    // },
    cellBackgroundStyle(status) {
      return {
        backgroundColor: this.getColor(status),
      };
    },

    getColor(status) {
      if (status === "open") return "#FF0000";
      else if (status === "wip") return "orange";
      else if (status === "n.rel.") return "#778899";
      else if (status === "closed") {
        return "#7bea7b";
      } else return null;
    },

    generateExcel() {
      const excelOperator = new ExcelOperator(
        this.deliverables,
        this.steps,
        this.responsibles,
        this.stepsFulfillment,
        this.totalFulfillment
      );
      const passObject = {
        deliverables: this.deliverables,
        headers: this.headers,
        steps: this.steps,
        responsibles: this.responsibles,
        stepsFulfillment: this.stepsFulfillment,
        totalFulfillment: this.totalFulfillment,
      };
      excelOperator.saveAsExcel(passObject);
    },

    async loadExcel() {
      if (this.file) {
        //TODO for later steps make another constructor for laod excel
        const excelOperator = new ExcelOperator(
          this.deliverables,
          this.steps,
          this.responsibles,
          this.stepsFulfillment,
          this.totalFulfillment
        );

        const passObject = {
          file: this.file,
          deliverables: this.deliverables,
          headers: this.headers,
          steps: this.steps,
          responsibles: this.responsibles,
          stepsFulfillment: this.stepsFulfillment,
          totalFulfillment: this.totalFulfillment,
        };

        let returnedProps = await excelOperator.loadExcel(passObject);

        util.recalculateAllFulfillments(returnedProps.deliverables, returnedProps.steps);

        this.$store.dispatch("setDeliverables", returnedProps.deliverables);
        this.$store.dispatch("setSteps", returnedProps.steps);
        this.$store.dispatch("setResponsibles", returnedProps.responsibles);
        this.$store.dispatch("setHeaders", returnedProps.headers);
        this.newRowCounter = 0;
      }
  
    },

    close1(item) {
      setTimeout(() => {
        this.isDialogOpen = false;
        item.showEditDialog = false;
      }, 500);
    },
    close() {},
    cancel() {},
    open(openedCell) {
      this.isDialogOpen = true;
      this.inputValue = openedCell;
    },
    changeCell(item, headerValue) {
      // console.log('chagne cell item', item)
      // console.log('change cell header value', headerValue);
      item[headerValue] = this.inputValue;
      // console.log('item header val', item)
      item.showEditDialog = false;
      this.isDialogOpen = false;
      this.calculateRowFulfillment(item);
      this.$store.dispatch("setDeliverables", this.deliverables);
    },

    changeHeader(header) {
      if (this.rules.required(this.inputValue.length) === true && this.rules.alreadyExist(this.inputValue) === true) {
        header.text = this.inputValue;

        this.$store.dispatch("setHeaders", this.headers);
      }
    },
    inputChanged(value, param) {
      // console.log('input changed value', value);
      if (param === "weight") {
        if (value !== "" && value > 0) {
          this.inputValue = value;
        }
      } else {
        this.inputValue = value;
      }
    },
    sortColumn(headerValue) {
      if (this.sortBy === headerValue) {
        this.sortDesc = true;

        if (this.rotateValues[headerValue] === 0) {
          this.sortDesc = false;
        }
      } else {
        this.sortDesc = false;
        this.sortBy = headerValue;
        this.rotateValues.id = 0;
        this.rotateValues.description = 0;
        this.rotateValues.weight = 0;
        this.rotateValues.fulfillment = 0;
      }
    },
    adjustSize() {
      const table = document.getElementsByTagName("table")[0];
      const tableWrapper = document.getElementsByClassName("v-data-table__wrapper")[0];
      if (this.adjustText === "Normal Size") {
        if (!this.horizontalAdjusted) {
          tableWrapper.style.width = tableWrapper.clientWidth * this.heightScale + "px";
        }
        table.style.transform = `scale(1)`;
        this.adjustText = "Fit On Page";
      } else {
        const containerWidth = tableWrapper.clientWidth;
        const containerHeight = tableWrapper.clientHeight;
        const scrollWidth = tableWrapper.scrollWidth;
        const scrollHeight = tableWrapper.scrollHeight;
        this.widthScale = containerWidth / scrollWidth;
        this.heightScale = containerHeight / scrollHeight;

        if (this.widthScale < this.heightScale) {
          table.style.transform = `scale(${this.widthScale})`;
          this.horizontalAdjusted = true;
        } else {
          table.style.transform = `scale(${this.heightScale})`;

          tableWrapper.style.width = tableWrapper.clientWidth / this.heightScale + "px";
          this.horizontalAdjusted = false;
        }
        this.adjustText = "Normal Size";
      }
    },
    // Added by MMG
    showDelete(idx) {
      this.deliverables[idx].showDeleteIcon = true;
    },
    unShowDelete(idx) {
      this.deliverables[idx].showDeleteIcon = false;
    },
    showColumnDelete(idx) {
      ++idx;
      this.headers[idx].columnDeleteIcon = true;
    },
    unShowColumnDelete(idx) {
      ++idx;
      this.headers[idx].columnDeleteIcon = false;
    },
    conformMessage(message, id, type) {
      if (type === "column") {
        if (this.showWeight === "Show Weight") {
          ++id;
        }
        if (id > 2 && id < this.responsibles.length + 3) {
          this.pressedId = id;
          this.pressedType = "responsible";
        } else {
          this.pressedId = id;
          this.pressedType = "step";
        }
        this.message = `Do you want to delete ${this.headers[id].text} column?`;
      } else {
        this.pressedId = id;
        this.pressedType = "Row";
        this.message = message;
      }

      this.toggleShowConformMessage();
    },
    deleteRow() {
      let id = this.pressedId;
      this.deliverables.splice(id, 1);
      for (id; id < this.deliverables.length; id++) {
        this.deliverables[id].id = this.deliverables[id].id - 1;
      }
      // &
      this.$store.dispatch("setDeliverables", this.deliverables);
      this.toggleShowConformMessage();
    },
    deleteColumn(headerValue) {
      let id = this.pressedId;
      // console.log('pressed id',id)
      // if (idx > 2 && this.steps.length > 1) {
      if (headerValue.includes("step")) {
        let stepNumber = id - (this.responsibles.length + 3);
        let lengthOfStep = this.steps.length;
        this.steps.splice(stepNumber, 1);
        this.headers.splice(id, 1);
        // console.log('step number', stepNumber)
        var a = 0;
        for (a; a < this.steps.length; a++) {
          this.steps[a].identity = `step${a + 1}`;
          this.steps[a].text = `step${a + 1}`;
        }
        var counter1 = 1;
        var b = 3 + this.responsibles.length;
        for (b; b < this.headers.length - 1; b++) {
          if (this.headers[b].text.includes("Step")) {
            this.headers[b].text = `Step${counter1}`;
          }
          this.headers[b].value = `step${counter1}`;
          counter1++;
        }
        var c = 0;
        for (c; c < this.deliverables.length; c++) {
          for (var d = stepNumber; d < this.steps.length; d++) {
            this.deliverables[c][`step${d + 1}`] = this.deliverables[c][`step${d + 2}`];
            // this.calculateRowFulfillment(this.deliverables[c]);
          }
          this.calculateRowFulfillment(this.deliverables[c]);
          // console.log('this is the col del func', lengthOfStep)
          // Deletes the last element of steps from delicerables array.
          delete this.deliverables[c][`step${lengthOfStep}`];
        }

        this.$store.dispatch("setHeaders", this.headers);
        this.$store.dispatch("setDeliverables", this.deliverables);
        this.$store.dispatch("setNextColumnName", this.$store.getters.getNextColumnName("Status"));
        this.toggleShowConformMessage();
        util.recalculateAllFulfillments(this.deliverables, this.steps);
      } else if (headerValue.includes("responsible")) {
        let y = 0;
        for (y; y < this.deliverables.length; y++) {
          let x = id;
          for (x; x < this.responsibles.length + 3; x++) {
            if (this.deliverables[y][`responsible${x - 1}`]) {
              this.deliverables[y][`responsible${x - 2}`] = this.deliverables[y][`responsible${x - 1}`];
            } else if (!this.deliverables[y][`responsible${x - 1}`]) {
              this.deliverables[y][`responsible${x - 2}`] = "";
            }
          }
        }

        let z = 0;
        for (z; z < this.deliverables.length; z++) {
          delete this.deliverables[z][`responsible${this.responsibles.length}`];
        }
        this.headers.splice(id, 1);
        this.responsibles.splice(id - 3, 1);

        var e = 0;
        for (e; e < this.responsibles.length; e++) {
          this.responsibles[e].identity = `responsible${e + 1}`;
          this.responsibles[e].text = `Responsible${e + 1}`;
        }
        var counter2 = 1;
        var f = 3;
        for (f; f < this.responsibles.length + 3; f++) {
          if (this.headers[f].text.includes("Responsible")) {
            this.headers[f].text = `Responsible${counter2}`;
          }
          this.headers[f].value = `responsible${counter2}`;
          counter2++;
        }

        this.$store.dispatch("setHeaders", this.headers);
        this.$store.dispatch("setResponsibles", this.responsibles);
        this.$store.dispatch("setDeliverables", this.deliverables);
        this.toggleShowConformMessage();
      }
    },
    toggleShowConformMessage() {
      this.showConformMessage = !this.showConformMessage;
    },
  },
};
</script>
